// Auto-generated by assets/gen_amber_favicon.py.
// The clocked amber clock icon, served at /favicon.ico so browsers that
// fetch it directly get a real image.
const PNG_B64 =
  "";

export function faviconResponse(): Response {
  const bin = atob(PNG_B64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return new Response(bytes, {
    headers: {
      "content-type": "image/png",
      "cache-control": "public, max-age=86400",
    },
  });
}
